using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time in ascending order
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Union-Find data structure
    vector<long long> parent(n);
    vector<long long> rank(n);

    function<long long(long long)> find = [&](long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    function<void(long long, long long)> unionSets = [&](long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
