                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    };

    // Initialize parent and rank
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }

    // Count the number of connected components
    long long components = n;

    // Iterate through edges in order of increasing time
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // Union the sets
        long long rootU = find(u);
        long long rootV = find(v);
        if (rootU != rootV) {
            unionSets(u, v);
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            return time;
        }
    }

    // If we haven't found the answer, return the time of the last edge
    return edges.back()[2];
